// src/utils/retry.ts
async function retryWithBackoff(operation, operationName, logger, maxRetries = 3, baseDelay = 1e3) {
  let lastError;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      logger.debug("EMBEDDED_PROVIDER", `Attempting ${operationName}`, {
        attempt,
        maxRetries
      });
      return await operation();
    } catch (error) {
      lastError = error;
      logger.warn("EMBEDDED_PROVIDER", `${operationName} failed`, {
        attempt,
        maxRetries,
        error: error instanceof Error ? error.message : String(error)
      });
      if (attempt === maxRetries) {
        logger.error("EMBEDDED_PROVIDER", `${operationName} failed after ${maxRetries} attempts`, {
          finalError: error instanceof Error ? error.message : String(error)
        });
        break;
      }
      const delay = baseDelay * Math.pow(2, attempt - 1);
      logger.debug("EMBEDDED_PROVIDER", `Retrying ${operationName} in ${delay}ms`, {
        attempt: attempt + 1,
        delay
      });
      await new Promise((resolve) => setTimeout(resolve, delay));
    }
  }
  throw lastError;
}

